// Determine UK hour, return early if outside 0700-2200
const now = new Date();
const london = new Intl.DateTimeFormat('en-GB',{timeZone:'Europe/London',hour:'2-digit',hour12:false}).format(now);
const hour = parseInt(london, 10);
if (hour < 7 || hour >= 22) {
  return [{json:{skip:true, reason:'outside warmup hours', hour}}];
}
return [{json:{skip:false, hour}}];

// For each source alias, pick a different destination alias and a corpus line
const aliases = $input.all().map(i => i.json);
const corpus = ['Quick note', 'Following up on', 'Reading on this', 'Worth a thought', 'Just sharing', 'Saw this', 'For your weekend', 'Briefly', 'A point worth flagging', 'On reflection'];
const out = [];
for (const src of aliases) {
  // pick a destination not equal to source
  const candidates = aliases.filter(a => a.id !== src.id);
  if (candidates.length === 0) continue;
  const dst = candidates[Math.floor(Math.random() * candidates.length)];
  const subject = corpus[Math.floor(Math.random() * corpus.length)];
  out.push({json: {
    from_alias_id: src.id,
    from_email: src.email,
    to_alias_id: dst.id,
    to_email: dst.email,
    subject,
    body: `${subject}.\n\nThis is a routine internal continuity check. Not actioned.\n\nTeam`,
    kind: 'warmup'
  }});
}
return out;
